20	export interface AppState {
21	  projects: Project[];
22	  threads: Thread[];
23	  threadsHydrated: boolean;
24	}
25	
26	const PERSISTED_STATE_KEY = "t3code:renderer-state:v8";
27	const LEGACY_PERSISTED_STATE_KEYS = [
28	  "t3code:renderer-state:v7",
29	  "t3code:renderer-state:v6",
30	  "t3code:renderer-state:v5",
31	  "t3code:renderer-state:v4",
32	  "t3code:renderer-state:v3",
33	  "codething:renderer-state:v4",
34	  "codething:renderer-state:v3",
35	  "codething:renderer-state:v2",
36	  "codething:renderer-state:v1",
37	] as const;
38	
39	const initialState: AppState = {
40	  projects: [],
41	  threads: [],
42	  threadsHydrated: false,
43	};
44	const persistedExpandedProjectCwds = new Set<string>();
45	
46	// ── Persist helpers ──────────────────────────────────────────────────
47	
48	function readPersistedState(): AppState {
49	  if (typeof window === "undefined") return initialState;
50	  try {
51	    const raw = window.localStorage.getItem(PERSISTED_STATE_KEY);
52	    if (!raw) return initialState;
53	    const parsed = JSON.parse(raw) as { expandedProjectCwds?: string[] };
54	    persistedExpandedProjectCwds.clear();
55	    for (const cwd of parsed.expandedProjectCwds ?? []) {
56	      if (typeof cwd === "string" && cwd.length > 0) {
57	        persistedExpandedProjectCwds.add(cwd);
58	      }
59	    }
60	    return { ...initialState };
61	  } catch {
62	    return initialState;
63	  }
64	}
65	
66	function persistState(state: AppState): void {
67	  if (typeof window === "undefined") return;
68	  try {
69	    window.localStorage.setItem(
70	      PERSISTED_STATE_KEY,
71	      JSON.stringify({
72	        expandedProjectCwds: state.projects
73	          .filter((project) => project.expanded)
74	          .map((project) => project.cwd),
75	      }),
76	    );
77	    for (const legacyKey of LEGACY_PERSISTED_STATE_KEYS) {
78	      window.localStorage.removeItem(legacyKey);
79	    }
80	  } catch {
81	    // Ignore quota/storage errors to avoid breaking chat UX.
82	  }
83	}
84	
85	// ── Pure helpers ──────────────────────────────────────────────────────
86	
87	function updateThread(
88	  threads: Thread[],
89	  threadId: ThreadId,
90	  updater: (t: Thread) => Thread,
91	): Thread[] {
92	  let changed = false;
93	  const next = threads.map((t) => {
94	    if (t.id !== threadId) return t;
95	    const updated = updater(t);
96	    if (updated !== t) changed = true;
97	    return updated;
98	  });
99	  return changed ? next : threads;
100	}

1	import { useCallback, useEffect, useSyncExternalStore } from "react";
2	
3	type Theme = "light" | "dark" | "system";
4	type ThemeSnapshot = {
5	  theme: Theme;
6	  systemDark: boolean;
7	};
8	
9	const STORAGE_KEY = "t3code:theme";
10	const MEDIA_QUERY = "(prefers-color-scheme: dark)";
11	
12	let listeners: Array<() => void> = [];
13	let lastSnapshot: ThemeSnapshot | null = null;
14	function emitChange() {
15	  for (const listener of listeners) listener();
16	}
17	
18	function getSystemDark(): boolean {
19	  return window.matchMedia(MEDIA_QUERY).matches;
20	}
21	
22	function getStored(): Theme {
23	  const raw = localStorage.getItem(STORAGE_KEY);
24	  if (raw === "light" || raw === "dark" || raw === "system") return raw;
25	  return "system";
26	}
27	
28	function applyTheme(theme: Theme, suppressTransitions = false) {
29	  if (suppressTransitions) {
30	    document.documentElement.classList.add("no-transitions");
31	  }
32	  const isDark = theme === "dark" || (theme === "system" && getSystemDark());
33	  document.documentElement.classList.toggle("dark", isDark);
34	  if (suppressTransitions) {
35	    // Force a reflow so the no-transitions class takes effect before removal
36	    // oxlint-disable-next-line no-unused-expressions
37	    document.documentElement.offsetHeight;
38	    requestAnimationFrame(() => {
39	      document.documentElement.classList.remove("no-transitions");
40	    });
41	  }
42	}
43	
44	// Apply immediately on module load to prevent flash
45	applyTheme(getStored());
46	
47	function getSnapshot(): ThemeSnapshot {
48	  const theme = getStored();
