import {
  createContext,
  createElement,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

// ── Constants ───────────────────────────────────────────────────────

const STORAGE_KEY = "t3code:theme";
const DEFAULT_THEME_ID = "t3-dark";

// ── Helpers ─────────────────────────────────────────────────────────

/**
 * Derive whether a hex background color is perceptually dark using
 * the ITU-R BT.601 luma formula.
 */
function isDarkBackground(hex: string): boolean {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return (0.299 * r + 0.587 * g + 0.114 * b) / 255 < 0.5;
}

function readStoredThemeId(): string {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw && getTheme(raw)) return raw;
  } catch {
    // localStorage may throw in restricted contexts.
  }
  return DEFAULT_THEME_ID;
}

function resolveTheme(id: string): Theme {
  return getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
}

// ── CSS custom property application ─────────────────────────────────

const THEME_COLOR_PROPERTIES: ReadonlyArray<[keyof Theme["colors"], string]> = [
  ["background", "--t3-background"],
  ["foreground", "--t3-foreground"],
  ["accent", "--t3-accent"],
  ["sidebar", "--t3-sidebar"],
  ["editor", "--t3-editor"],
  ["terminal", "--t3-terminal"],
  ["statusBar", "--t3-status-bar"],
];

function applyThemeToDOM(theme: Theme, suppressTransitions = false) {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Toggle dark class for Tailwind @variant dark
  root.classList.toggle("dark", isDarkBackground(theme.colors.background));

  // Apply theme CSS custom properties
  for (const [key, property] of THEME_COLOR_PROPERTIES) {
    root.style.setProperty(property, theme.colors[key]);
  }
  root.style.setProperty("--t3-font-family", theme.fontFamily);
  root.style.setProperty("--t3-font-size", `${String(theme.fontSize)}px`);

  if (suppressTransitions) {
    // Force reflow so the no-transitions class suppresses animations
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// ── Eager initialisation (prevent flash) ────────────────────────────

applyThemeToDOM(resolveTheme(readStoredThemeId()));

// ── External store ──────────────────────────────────────────────────

let listeners: Array<() => void> = [];
let lastSnapshot: { themeId: string } | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSnapshot(): { themeId: string } {
  const themeId = readStoredThemeId();
  if (lastSnapshot && lastSnapshot.themeId === themeId) {
    return lastSnapshot;
  }
  lastSnapshot = { themeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync when another tab changes the stored theme
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyThemeToDOM(resolveTheme(readStoredThemeId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ── React context ───────────────────────────────────────────────────

interface ThemeContextValue {
  /** The currently active theme definition. */
  theme: Theme;
  /** Switch to a different theme by its id. */
  setTheme: (id: string) => void;
  /** All available themes. */
  availableThemes: readonly Theme[];
  /** Resolved colour-scheme — always "light" or "dark". */
  resolvedTheme: "light" | "dark";
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

// ── ThemeProvider ───────────────────────────────────────────────────

export function ThemeProvider({ children }: { children: ReactNode }) {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = resolveTheme(snapshot.themeId);
  const availableThemes = useMemo(() => listThemes(), []);
  const resolvedTheme: "light" | "dark" = isDarkBackground(theme.colors.background)
    ? "dark"
    : "light";

  const setTheme = useCallback((id: string) => {
    const next = resolveTheme(id);
    localStorage.setItem(STORAGE_KEY, next.id);
    applyThemeToDOM(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync when the theme value changes
  useEffect(() => {
    applyThemeToDOM(theme);
  }, [theme]);

  const value = useMemo<ThemeContextValue>(
    () => ({ theme, setTheme, availableThemes, resolvedTheme }),
    [theme, setTheme, availableThemes, resolvedTheme],
  );

  return createElement(ThemeContext, { value }, children);
}

// ── Hook ────────────────────────────────────────────────────────────

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used within a <ThemeProvider>");
  }
  return ctx;
}

