import type { ThemeColors } from "@t3tools/shared/themes";

import { useTheme } from "../hooks/useTheme";

const SWATCH_KEYS: ReadonlyArray<keyof ThemeColors> = [
  "background",
  "foreground",
  "accent",
  "sidebar",
  "editor",
  "terminal",
  "statusBar",
];

export function ThemeSelector() {
  const { theme, setTheme, availableThemes, resolvedTheme } = useTheme();

  return (
    <div>
      <div className="space-y-2" role="radiogroup" aria-label="Theme">
        {availableThemes.map((t) => {
          const selected = theme.id === t.id;
          return (
            <button
              key={t.id}
              type="button"
              role="radio"
              aria-checked={selected}
              className={`flex w-full items-center justify-between rounded-lg border px-3 py-2.5 text-left transition-colors ${
                selected
                  ? "border-primary/60 bg-primary/8 text-foreground"
                  : "border-border bg-background text-muted-foreground hover:bg-accent"
              }`}
              onClick={() => setTheme(t.id)}
            >
              <div className="flex items-center gap-3">
                <div className="flex gap-1.5" aria-hidden="true">
                  {SWATCH_KEYS.map((key) => (
                    <span
                      key={key}
                      className="block size-4 rounded-full border border-black/10 dark:border-white/10"
                      style={{ backgroundColor: t.colors[key] }}
                      title={key}
                    />
                  ))}
                </div>
                <span className="text-sm font-medium">{t.name}</span>
              </div>

              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Selected
                </span>
              ) : null}
            </button>
          );
        })}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">
          {theme.name} ({resolvedTheme})
        </span>
      </p>
    </div>
  );
}

